SELECT * FROM t_exchange_order WHERE status IN
#{status,typeHandler=org.apache.ibatis.type.EnumOrdinalTypeHandler}
ORDER BY create_time ASC

mapper.update:
UPDATE t_exchange_order
SET
qty = CASE id

    WHEN #{order.id} THEN #{order.qty}

END,
status = CASE id

    WHEN #{order.id} THEN #{order.status,typeHandler=org.apache.ibatis.type.EnumOrdinalTypeHandler}

END,
version = version + 1
WHERE id IN

    #{order.id}

AND version IN

    #{order.version}
